import os

def delete_directory(path):
    # Check if the path exists
    if not os.path.exists(path):
        return

    # Check if the path is a directory
    if not os.path.isdir(path):
        return

    # Try to delete the directory
    try:
        # Get a list of files and subdirectories in the directory
        files_and_subdirectories = os.listdir(path)

        # Iterate over each item in the directory
        for item in files_and_subdirectories:
            # Construct the full path to the item
            item_path = os.path.join(path, item)

            # If the item is a directory, recursively delete it
            if os.path.isdir(item_path):
                delete_directory(item_path)

            # If the item is a file, try to delete it
            try:
                os.remove(item_path)
            except OSError:
                pass

        # Try to delete the directory itself
        try:
            os.rmdir(path)
        except OSError:
            pass

    except OSError:
        pass
